public void testGetInitialDomainWithLargeDenominatorDF() throws Exception {
    org.apache.commons.math.distribution.FDistributionImpl fd =
        new org.apache.commons.math.distribution.FDistributionImpl(5.0, 10.0);
    double p = fd.cumulativeProbability(1.5);
    double x = fd.inverseCumulativeProbability(p);
    assertEquals(1.5, x, 1.0e-5);
}

public void testGetInitialDomainWithDenominatorDFExactlyTwo() throws Exception {
    org.apache.commons.math.distribution.FDistributionImpl fd =
        new org.apache.commons.math.distribution.FDistributionImpl(3.0, 2.0);
    double p = fd.cumulativeProbability(2.5);
    double x = fd.inverseCumulativeProbability(p);
    assertEquals(2.5, x, 1.0e-5);
}

public void testGetInitialDomainWithDenominatorDFBetweenOneAndTwo() throws Exception {
    org.apache.commons.math.distribution.FDistributionImpl fd =
        new org.apache.commons.math.distribution.FDistributionImpl(4.0, 1.5);
    double p = fd.cumulativeProbability(1.8);
    double x = fd.inverseCumulativeProbability(p);
    assertEquals(1.8, x, 1.0e-5);
}
